/* === DMA 循环缓冲区架构分层 === */

typedef struct {
    uint8_t *buffer;          /* 指向 DMA 传输的内存区域 */
    uint16_t  capacity;       /* 缓冲区总容量（字节）*/
    uint16_t  head;           /* DMA 写入位置（硬件维护）*/
    uint16_t  tail;           /* CPU 读取位置（软件维护）*/
    uint16_t  available;      /* 可读字节数 = head - tail */
} dma_circbuf_t;

/* 初始化：分配缓冲区，配置 DMA，启动传输 */
dma_circbuf_t *circbuf_create(uint8_t *mem, uint16_t size);

/* 读取新数据：返回实际可读字节数，更新 tail */
uint16_t circbuf_read(dma_circbuf_t *cb, uint8_t *out, uint16_t max_len);

/* 丢弃未读数据：推进 tail 到 head（用于错误恢复）*/
void circbuf_discard(dma_circbuf_t *cb);

/* === USART3 + DMA2 Stream5 循环接收（STM32F4xx HAL）=== */
#include "stm32f4xx_hal.h"

#define RX_BUF_SIZE   256
static uint8_t rx_buffer[RX_BUF_SIZE];
static volatile uint16_t dma_bytes_transferred;  /* NDTR 镜像 */

UART_HandleTypeDef huart3;
DMA_HandleTypeDef hdma_usart3_rx;

/* 初始化 DMA2 Stream5 用于 USART3_RX 循环接收 */
void dma_usart_init(void) {
    __HAL_RCC_DMA2_CLK_ENABLE();
    __HAL_RCC_USART3_CLK_ENABLE();

    /* DMA2 Stream5, Channel 4 = USART3_RX */
    hdma_usart_rx.Instance                  = DMA2_Stream5;
    hdma_usart_rx.Init.Channel              = DMA_CHANNEL_4;
    hdma_usart_rx.Init.Direction            = DMA_PERIPH_TO_MEMORY;
    hdma_usart_rx.Init.PeriphInc            = DMA_PINC_DISABLE;
    hdma_usart_rx.Init.MemInc               = DMA_MINC_ENABLE;
    hdma_usart_rx.Init.PeriphDataAlignment  = DMA_PDATAALIGN_BYTE;
    hdma_usart_rx.Init.MemDataAlignment     = DMA_MDATAALIGN_BYTE;
    hdma_usart_rx.Init.Mode                 = DMA_CIRCULAR;  /* 循环模式 */
    hdma_usart_rx.Init.Priority             = DMA_PRIORITY_VERY_HIGH;
    hdma_usart_rx.Init.FIFOMode             = DMA_FIFOMODE_DISABLE;
    hdma_usart_rx.Instance->NDTR            = RX_BUF_SIZE;  /* 安全初始化 */

    HAL_DMA_Init(&hdma_usart_rx);
    __HAL_LINKDMA(&huart3, hdmarx, hdma_usart_rx);

    /* 使能 DMA 传输完成中断 */
    HAL_NVIC_SetPriority(DMA2_Stream5_IRQn, 6, 0);
    HAL_NVIC_EnableIRQ(DMA2_Stream5_IRQn);

    /* 启动 DMA 循环接收：传输 RX_BUF_SIZE 个字节 */
    HAL_UART_Receive_DMA(&huart3, rx_buffer, RX_BUF_SIZE);
}

/* DMA 传输完成回调：每 256 字节触发一次（循环模式）*/
void DMA2_Stream5_IRQHandler(void) {
    HAL_DMA_IRQHandler(&hdma_usart_rx);
}

void HAL_UART_RxCpltCallback(DMA_HandleTypeDef *hdma) {
    /* 在循环模式下，这个回调每 256 字节触发一次 */
    /* 读取 NDTR 寄存器获取 DMA 实际剩余传输量 */
    dma_bytes_transferred = hdma->Instance->NDTR;
    /* 已写入字节数 = RX_BUF_SIZE - NDTR */
    uint16_t written = RX_BUF_SIZE - dma_bytes_transferred;
    /* 通知应用层有新数据可用 */
    process_uart_data(rx_buffer, written);
}

/* === 陷阱演示：撕裂数据的双缓冲修复 === */

/* ❌ 错误做法：单缓冲区 + volatile（仍然有撕裂风险）*/
static volatile uint8_t single_buf[256];

/* ✅ 正确做法：双缓冲（Ping-Pong）消除撕裂 */
#define PING_PONG_SIZE  256
typedef struct {
    uint8_t ping[PING_PONG_SIZE];
    uint8_t pong[PING_PONG_SIZE];
    uint8_t *active;    /* 当前 DMA 写入的缓冲区 */
    uint8_t *complete;  /* 上一个完整缓冲区（CPU 可读）*/
    _Bool   swap_flag;  /* 缓冲区交换标志 */
} ping_pong_buf_t;

static ping_pong_buf_t pp_buf;

/* 在 DMA_TC 回调中交换缓冲区 */
void DMA2_Stream5_IRQHandler(void) {
    HAL_DMA_IRQHandler(&hdma_usart3_rx);

    /* 交换 active 和 complete 指针 */
    pp_buf.swap_flag = true;
}

/* CPU 侧：检查是否有完整缓冲区可读 */
void cpu_process_loop(void) {
    if (pp_buf.swap_flag) {
        /* 等待 DMA 完成当前传输后再交换 */
        __DSB();  /* 数据同步屏障 */

        uint8_t *temp = pp_buf.active;
        pp_buf.active = pp_buf.complete;
        pp_buf.complete = temp;
        pp_buf.swap_flag = false;

        /* 现在 pp_buf.complete 包含完整的 256 字节数据 */
        parse_modbus_frame(pp_buf.complete, PING_PONG_SIZE);
    }
}

/* === 重构前：轮询 UART 接收（阻塞模式，CPU 利用率 ~100%）=== */
void main_loop_polling(void) {
    uint8_t rx_byte;
    while (1) {
        /* 阻塞等待 —— CPU 在这里空等，啥也干不了 */
        HAL_UART_Receive(&huart3, &rx_byte, 1, HAL_MAX_DELAY);

        /* 收到一个字节后处理 —— 但可能等了很久才到这里 */
        process_byte(rx_byte);

        /* 注意：如果有 256 字节突发包，这里要循环 256 次，
           每次都要等 UART_DR 寄存器准备好，总耗时 ~22ms */
    }
}

/* === 重构后：DMA 循环接收 + 事件驱动处理（CPU 利用率 ~5%）=== */

/* 第一步：全局缓冲区（DMA 直接写入）*/
#define RX_BUF_SIZE  256
static uint8_t rx_buffer[RX_BUF_SIZE];
static volatile uint16_t rx_head;  /* DMA 写入位置 */
static volatile uint16_t rx_tail;  /* CPU 读取位置 */
static volatile _Bool  data_ready; /* 新数据可用标志 */

/* 第二步：初始化 DMA 循环接收 */
void uart_dma_init(void) {
    /* 配置 DMA2 Stream5, Channel 4 为循环模式 */
    hdma_usart3_rx.Instance = DMA2_Stream5;
    hdma_usart3_rx.Init.Mode = DMA_CIRCULAR;
    HAL_DMA_Init(&hdma_usart3_rx);
    __HAL_LINKDMA(&huart3, hdmarx, hdma_usart3_rx);

    /* 启动 DMA 接收：持续将 UART_DR 搬运到 rx_buffer */
    HAL_UART_Receive_DMA(&huart3, rx_buffer, RX_BUF_SIZE);
}

/* 第三步：DMA 传输完成回调 */
void HAL_UART_RxCpltCallback(DMA_HandleTypeDef *hdma) {
    /* DMA 完成了 256 字节的循环传输，标记数据可用 */
    data_ready = true;
}

/* 第四步：主循环 —— 非阻塞检查，有数据才处理 */
void main_loop_dma(void) {
    static uint8_t frame_buf[256];

    while (1) {
        /* 检查是否有新数据 —— 不阻塞，立即返回 */
        if (data_ready) {
            data_ready = false;

            /* 将 DMA 缓冲区的数据拷贝到本地帧缓冲区 */
            /* 注意：这里拷贝的是完整的一帧（256 字节），
               因为 DMA 循环模式下我们保证拿到的是完整的一批数据 */
            memcpy(frame_buf, rx_buffer, RX_BUF_SIZE);

            /* 处理帧数据 —— 此时 CPU 可以自由耗时处理，
               因为 DMA 已经在后台继续收集下一批数据了 */
            parse_modbus_frame(frame_buf, RX_BUF_SIZE);
        }

        /* CPU 空闲时可以处理其他任务 —— 这才是 DMA 循环接收的核心价值 */
        motor_control_task();
        can_bus_task();
        vTaskDelay(pdMS_TO_TICKS(1));  /* FreeRTOS 空闲周期 */
    }
}
